st.markdown("""
<style>
header[data-testid="stHeader"] { display: none; }
#MainMenu { visibility: hidden; }
footer { visibility: hidden; }
.block-container { padding: 0 !important; max-width: 100% !important; }
.stApp { background: #070910; }
iframe { display: block; }
</style>
""", unsafe_allow_html=True)

html = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<style>\n:root{\n  --bg:#070910;\n  --panel:#111827;\n  --cell:#172033;\n  --cell2:#1b2740;\n  --gold:#ffd166;\n  --gold2:#ffb703;\n  --text:#f8fafc;\n  --muted:#a8b3c7;\n  --marked:#138a52;\n  --free:#532e86;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  min-height:100%;\n  background:radial-gradient(circle at top,rgba(255,209,102,.10),transparent 28%),#070910;\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  overflow-x:hidden;\n}\n.app{\n  width:min(94vw,620px);\n  margin:0 auto;\n  padding:12px 8px 28px;\n}\n.header{\n  text-align:center;\n  margin-bottom:8px;\n}\n.title{\n  color:var(--gold);\n  font-size:clamp(34px,7vw,58px);\n  line-height:.95;\n  font-weight:900;\n  letter-spacing:-.04em;\n  text-shadow:0 0 14px rgba(255,209,102,.28);\n  animation:titleGlow 3.5s ease-in-out infinite alternate;\n}\n.title span{\n  display:block;\n  font-size:.58em;\n  margin-top:4px;\n}\n@keyframes titleGlow{\n  from{filter:brightness(.95)}\n  to{filter:brightness(1.15)}\n}\n.toolbar{\n  width:max-content;\n  max-width:100%;\n  margin:0 auto 12px;\n  display:flex;\n  gap:6px;\n  align-items:center;\n  background:#111827;\n  border:1px solid rgba(255,209,102,.24);\n  padding:6px;\n}\n.icon-btn{\n  width:36px;\n  height:36px;\n  border:1px solid rgba(255,209,102,.35);\n  background:#251a08;\n  color:var(--gold);\n  cursor:pointer;\n  display:grid;\n  place-items:center;\n  transition:transform .12s ease,filter .12s ease,border-color .12s ease;\n}\n.icon-btn:hover{transform:translateY(-1px);filter:brightness(1.15);border-color:var(--gold)}\n.icon-btn:active{transform:scale(.96)}\n.icon-btn svg{width:18px;height:18px;stroke:currentColor;fill:none;stroke-width:2.4;stroke-linecap:round;stroke-linejoin:round}\n.board-select{\n  height:36px;\n  border:1px solid rgba(255,209,102,.35);\n  background:#111827;\n  color:var(--gold);\n  font-weight:800;\n  padding:0 8px;\n  outline:none;\n}\n.boards{\n  display:grid;\n  gap:14px;\n  justify-content:center;\n}\n.boards.one{grid-template-columns:minmax(300px,min(78vmin,520px))}\n.boards.two,.boards.three,.boards.four{\n  grid-template-columns:repeat(2,minmax(260px,1fr));\n  width:min(94vw,880px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.board-shell{\n  background:linear-gradient(135deg,#ffb703,#ffd166,#7c5200);\n  padding:5px;\n  box-shadow:0 0 24px rgba(255,183,3,.22);\n}\n.board{\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  gap:3px;\n  padding:5px;\n  background:#2b210e;\n  aspect-ratio:1/1;\n}\n.cell{\n  position:relative;\n  background:var(--cell);\n  color:var(--text);\n  border:1px solid #30405a;\n  font-size:clamp(9px,1.45vw,13px);\n  line-height:1.08;\n  font-weight:800;\n  text-align:center;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  padding:5px;\n  cursor:pointer;\n  user-select:none;\n  overflow:hidden;\n  transition:background .14s ease,transform .14s ease,filter .14s ease,box-shadow .14s ease;\n}\n.cell:nth-child(even){background:var(--cell2)}\n.cell:hover{\n  transform:translateY(-1px);\n  filter:brightness(1.1);\n  box-shadow:inset 0 0 0 1px rgba(255,209,102,.45);\n}\n.cell.free{\n  background:var(--free)!important;\n  color:var(--gold);\n  font-size:clamp(13px,2vw,18px);\n  font-style:italic;\n  cursor:default;\n}\n.cell.free:hover{transform:none;filter:none}\n.cell.marked{\n  background:var(--marked)!important;\n  color:#ecfff4;\n  animation:mark .18s ease;\n}\n.cell.marked:after{\n  content:\"\u2713\";\n  position:absolute;\n  right:6px;\n  bottom:1px;\n  font-size:18px;\n  opacity:.38;\n}\n@keyframes mark{\n  0%{transform:scale(.97);filter:brightness(1.25)}\n  100%{transform:scale(1);filter:brightness(1)}\n}\n.cell.rolling:not(.free){\n  animation:rollCell .25s ease;\n}\n@keyframes rollCell{\n  0%{filter:brightness(.75);transform:translateY(2px)}\n  60%{filter:brightness(1.25);transform:translateY(-2px)}\n  100%{filter:brightness(1);transform:translateY(0)}\n}\n.modal-backdrop{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,.74);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:20;\n  padding:20px;\n}\n.modal-backdrop.show{display:flex}\n.modal{\n  width:min(92vw,390px);\n  background:#111827;\n  border:1px solid rgba(255,209,102,.32);\n  box-shadow:0 0 36px rgba(0,0,0,.55);\n  padding:18px;\n}\n.modal h2{\n  margin:0 0 12px;\n  color:var(--gold);\n  font-size:30px;\n}\n.modal p{\n  margin:8px 0;\n  font-weight:700;\n}\n.close{\n  margin-top:14px;\n  width:100%;\n  height:36px;\n  border:1px solid rgba(255,209,102,.35);\n  background:#251a08;\n  color:var(--gold);\n  font-weight:900;\n  cursor:pointer;\n}\n.bingo-modal .modal{text-align:center}\n.bingo-modal h2{\n  font-size:clamp(52px,10vw,86px);\n  text-shadow:0 0 16px var(--gold);\n  animation:bingoPulse .75s ease-in-out infinite alternate;\n}\n@keyframes bingoPulse{\n  from{transform:scale(1);filter:brightness(1)}\n  to{transform:scale(1.04);filter:brightness(1.25)}\n}\n.confetti{\n  position:fixed;\n  top:-20px;\n  z-index:30;\n  font-size:18px;\n  animation:fall 1.2s linear forwards;\n}\n@keyframes fall{\n  to{transform:translateY(110vh) rotate(360deg);opacity:.2}\n}\n@media(max-width:760px){\n  .boards.two,.boards.three,.boards.four{\n    grid-template-columns:1fr;\n    width:min(94vw,520px);\n  }\n  .cell,.boards.two .cell,.boards.three .cell,.boards.four .cell{\n    font-size:clamp(9px,2.35vw,12px);\n  }\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n  <div class=\"header\">\n    <div class=\"title\">Wings of Glory<span>Low Rank Bingo</span></div>\n  </div>\n\n  <div class=\"toolbar\">\n    <button class=\"icon-btn\" title=\"Roll\" onclick=\"rollBoards()\">\n      <svg viewBox=\"0 0 24 24\"><rect x=\"4\" y=\"4\" width=\"16\" height=\"16\"></rect><circle cx=\"8\" cy=\"8\" r=\"1\"></circle><circle cx=\"16\" cy=\"8\" r=\"1\"></circle><circle cx=\"12\" cy=\"12\" r=\"1\"></circle><circle cx=\"8\" cy=\"16\" r=\"1\"></circle><circle cx=\"16\" cy=\"16\" r=\"1\"></circle></svg>\n    </button>\n    <button class=\"icon-btn\" title=\"Reset\" onclick=\"resetMarks()\">\n      <svg viewBox=\"0 0 24 24\"><path d=\"M4 12a8 8 0 1 0 3-6\"></path><path d=\"M4 4v6h6\"></path></svg>\n    </button>\n    <button class=\"icon-btn\" title=\"Rules\" onclick=\"openRules()\">\n      <svg viewBox=\"0 0 24 24\"><path d=\"M9.5 9a2.5 2.5 0 1 1 4.3 1.7c-1.2 1-1.8 1.5-1.8 3.1\"></path><path d=\"M12 18h.01\"></path><circle cx=\"12\" cy=\"12\" r=\"9\"></circle></svg>\n    </button>\n    <select class=\"board-select\" onchange=\"setBoardCount(this.value)\">\n      <option value=\"1\">1 board</option>\n      <option value=\"2\">2 boards</option>\n      <option value=\"3\">3 boards</option>\n      <option value=\"4\">4 boards</option>\n    </select>\n  </div>\n\n  <div id=\"boards\" class=\"boards one\"></div>\n</div>\n\n<div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\">\n  <div class=\"modal\">\n    <h2>Rules</h2>\n    <p>\u2022 Click a square when it happens.</p>\n    <p>\u2022 Free space starts marked.</p>\n    <p>\u2022 5 in a row wins.</p>\n    <p>\u2022 Rows, columns, diagonals count.</p>\n    <button class=\"close\" onclick=\"hideRules()\">Close</button>\n  </div>\n</div>\n\n<div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\">\n  <div class=\"modal\">\n    <h2>BINGO!</h2>\n    <button class=\"close\" onclick=\"hideBingo()\">Close</button>\n  </div>\n</div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards=[];\nlet marked=[];\nlet boardCount=1;\nlet rolling=false;\n\nfunction shuffle(arr){\n  const a=[...arr];\n  for(let i=a.length-1;i>0;i--){\n    const j=Math.floor(Math.random()*(i+1));\n    [a[i],a[j]]=[a[j],a[i]];\n  }\n  return a;\n}\nfunction makeBoard(){\n  const items=shuffle(ITEMS);\n  const board=[];\n  let idx=0;\n  for(let i=0;i<25;i++){\n    board.push(i===12 ? \"FREE SPACE\" : items[idx++]);\n  }\n  return board;\n}\nfunction classForCount(){\n  if(boardCount===1)return\"one\";\n  if(boardCount===2)return\"two\";\n  if(boardCount===3)return\"three\";\n  return\"four\";\n}\nfunction setBoardCount(n){\n  boardCount=Math.max(1,Math.min(4,Number(n)));\n  while(boards.length<boardCount){\n    boards.push(makeBoard());\n    marked.push(new Set([12]));\n  }\n  while(boards.length>boardCount){\n    boards.pop();\n    marked.pop();\n  }\n  render();\n}\nfunction render(){\n  const root=document.getElementById(\"boards\");\n  root.className=\"boards \"+classForCount();\n  root.innerHTML=\"\";\n  for(let b=0;b<boardCount;b++){\n    const shell=document.createElement(\"div\");\n    shell.className=\"board-shell\";\n    const board=document.createElement(\"div\");\n    board.className=\"board\";\n    for(let i=0;i<25;i++){\n      const cell=document.createElement(\"div\");\n      cell.className=\"cell\";\n      if(i===12)cell.classList.add(\"free\");\n      if(marked[b].has(i))cell.classList.add(\"marked\");\n      cell.textContent=boards[b][i];\n      cell.onclick=()=>toggleCell(b,i);\n      board.appendChild(cell);\n    }\n    shell.appendChild(board);\n    root.appendChild(shell);\n  }\n}\nfunction toggleCell(b,i){\n  if(i===12||rolling)return;\n  const boardEl=document.getElementById(\"boards\").children[b].querySelector(\".board\");\n  const cell=boardEl.children[i];\n  if(marked[b].has(i)){\n    marked[b].delete(i);\n    cell.classList.remove(\"marked\");\n  }else{\n    marked[b].add(i);\n    cell.classList.add(\"marked\");\n  }\n  if(hasBingo(marked[b]))showBingo();\n}\nfunction winLines(){\n  const lines=[];\n  for(let r=0;r<5;r++)lines.push([0,1,2,3,4].map(c=>r*5+c));\n  for(let c=0;c<5;c++)lines.push([0,1,2,3,4].map(r=>r*5+c));\n  lines.push([0,6,12,18,24]);\n  lines.push([4,8,12,16,20]);\n  return lines;\n}\nfunction hasBingo(set){\n  return winLines().some(line=>line.every(i=>set.has(i)));\n}\nfunction rollBoards(){\n  if(rolling)return;\n  rolling=true;\n  const cells=()=>Array.from(document.querySelectorAll(\".cell:not(.free)\"));\n  let steps=9;\n  function spin(step){\n    const temp=Array.from({length:boardCount},()=>makeBoard());\n    cells().forEach((cell,idx)=>{\n      const boardIndex=Math.floor(idx/24);\n      const innerIndex=idx%24;\n      const pool=temp[boardIndex].filter((_,i)=>i!==12);\n      cell.textContent=pool[innerIndex]||ITEMS[Math.floor(Math.random()*ITEMS.length)];\n      cell.classList.remove(\"rolling\");\n      void cell.offsetWidth;\n      cell.classList.add(\"rolling\");\n    });\n    if(step<steps){\n      setTimeout(()=>spin(step+1),60+step*12);\n    }else{\n      boards=Array.from({length:boardCount},()=>makeBoard());\n      marked=Array.from({length:boardCount},()=>new Set([12]));\n      rolling=false;\n      render();\n    }\n  }\n  spin(0);\n}\nfunction resetMarks(){\n  marked=Array.from({length:boardCount},()=>new Set([12]));\n  render();\n}\nfunction openRules(){document.getElementById(\"rulesModal\").classList.add(\"show\")}\nfunction hideRules(){document.getElementById(\"rulesModal\").classList.remove(\"show\")}\nfunction closeRules(e){if(e.target.id===\"rulesModal\")hideRules()}\nfunction showBingo(){document.getElementById(\"bingoModal\").classList.add(\"show\");confettiBurst()}\nfunction hideBingo(){document.getElementById(\"bingoModal\").classList.remove(\"show\")}\nfunction confettiBurst(){\n  const shapes=[\"\u2726\",\"\u2605\",\"\u2666\",\"\u25cf\",\"\u2713\"];\n  const colors=[\"#ffd166\",\"#138a52\",\"#ffffff\",\"#ffb703\"];\n  for(let i=0;i<26;i++){\n    const s=document.createElement(\"div\");\n    s.className=\"confetti\";\n    s.textContent=shapes[Math.floor(Math.random()*shapes.length)];\n    s.style.left=Math.random()*100+\"vw\";\n    s.style.color=colors[Math.floor(Math.random()*colors.length)];\n    s.style.animationDelay=Math.random()*.12+\"s\";\n    document.body.appendChild(s);\n    setTimeout(()=>s.remove(),1400);\n  }\n}\ndocument.addEventListener(\"keydown\",e=>{\n  if(e.key===\"Escape\"){hideRules();hideBingo();}\n});\nboards=[makeBoard()];\nmarked=[new Set([12])];\nrender();\n</script>\n</body>\n</html>\n"

components.html(html, height=900, scrolling=True)
